UPDATE wp_posts SET
  post_title = 'DigiWin Blog Single Template',
  post_content = '<!-- wp:divi/placeholder -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Blog Hero"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero Content"}}},"decoration":{}}} -->\n<!-- wp:divi/code {"content":{"innerContent":{"desktop":{"value":"<style>\\n/* Beat Divi framework reset: .et-l--body .et_pb_section[class*=\\"tb_body\\"].et_section_regular { background: none !important } */\\n.et-l--body .et_pb_section.et_pb_section_0_tb_body.et_section_regular[class] {\\n  background: linear-gradient(135deg, #000432 0%, #000864 40%, #001080 100%) !important;\\n}\\n.et-l--body .et_pb_section.et_pb_section_1_tb_body.et_section_regular[class] {\\n  background: #fff !important;\\n}\\n.et-l--body .et_pb_section.et_pb_section_2_tb_body.et_section_regular[class] {\\n  background: #F5F7FA !important;\\n}\\n.et-l--body .et_pb_section.et_pb_section_3_tb_body.et_section_regular[class] {\\n  background: linear-gradient(135deg, #000432 0%, #000864 50%, #003CC8 100%) !important;\\n}\\n/* News post overrides (green badge hero, dark related) */\\nbody.category-industry-news .et-l--body .et_pb_section.et_pb_section_0_tb_body.et_section_regular[class] {\\n  background-size: cover !important;\\n  background-position: center !important;\\n}\\nbody.category-industry-news .et-l--body .et_pb_section.et_pb_section_2_tb_body.et_section_regular[class] {\\n  background: linear-gradient(135deg, #000432 0%, #000864 100%) !important;\\n}\\n</style>\\n<div class=\\"dw-blog-nav\\">\\n  <a href=\\"/blog/\\" class=\\"dw-blog-back-link dw-back-blog\\">\\n    <svg viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\"><path d=\\"M19 12H5M12 19l-7-7 7-7\\"/></svg>\\n    Back to Blog\\n  </a>\\n  <a href=\\"/news/\\" class=\\"dw-blog-back-link dw-back-news\\">\\n    <svg viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\"><path d=\\"M19 12H5M12 19l-7-7 7-7\\"/></svg>\\n    Back to News &amp; Events\\n  </a>\\n</div>"}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero Nav Links"}}}}} /-->\n<!-- wp:divi/post-title {"featuredImage":{"advanced":{"enabled":{"desktop":{"value":"off"}}}},"title":{"decoration":{"font":{"font":{"desktop":{"value":{"family":"Noto Sans","weight":"700","size":"42px","lineHeight":"1.2em","color":"#FFFFFF"}},"tablet":{"value":{"size":"32px"}},"phone":{"value":{"size":"24px"}}}}}},"meta":{"decoration":{"font":{"font":{"desktop":{"value":{"family":"Noto Sans","weight":"400","color":"rgba(255,255,255,0.8)","size":"14px"}}}}},"advanced":{"showAuthor":{"desktop":{"value":"off"}},"showDate":{"desktop":{"value":"on"}},"showCategories":{"desktop":{"value":"on"}},"showComments":{"desktop":{"value":"off"}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Dynamic Post Title"}}},"advanced":{"text":{"text":{"desktop":{"value":{"orientation":"left"}}}}}},"builderVersion":"5.0.0-public-beta.8"} --><!-- /wp:divi/post-title -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Blog Content"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Content Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Content Column"}}},"decoration":{}}} -->\n<!-- wp:divi/post-content {"module":{"meta":{"adminLabel":{"desktop":{"value":"Dynamic Post Content"}}},"decoration":{"bodyFont":{"body":{"font":{"desktop":{"value":{"family":"Noto Sans","weight":"400","size":"16px","lineHeight":"1.8em","color":"#333333"}},"tablet":{"value":{"size":"15px"}},"phone":{"value":{"size":"14px"}}}}},"headingFont":{"h2":{"font":{"desktop":{"value":{"family":"Noto Sans","weight":"600","size":"28px","lineHeight":"1.3em","color":"#000864"}}}},"h3":{"font":{"desktop":{"value":{"family":"Noto Sans","weight":"600","size":"22px","lineHeight":"1.35em","color":"#000864"}}}},"h4":{"font":{"desktop":{"value":{"family":"Noto Sans","weight":"600","size":"18px","lineHeight":"1.4em","color":"#000864"}}}}}}},"builderVersion":"5.0.0-public-beta.8"} --><!-- /wp:divi/post-content -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Related Articles"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Related Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Related Column"}}},"decoration":{}}} -->\n<!-- wp:divi/code {"content":{"innerContent":{"desktop":{"value":"<h2 class=\\"dw-blog-related-heading\\">Related Articles</h2>"}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Related Heading"}}}}} /-->\n<!-- wp:divi/blog {"fullwidth":{"advanced":{"enable":{"desktop":{"value":"off"}}}},"readMore":{"advanced":{"enable":{"desktop":{"value":"on"}}},"decoration":{"font":{"font":{"desktop":{"value":{"family":"Noto Sans","weight":"600","color":"#00AFF0"}}}}}},"meta":{"advanced":{"showAuthor":{"desktop":{"value":"off"}}},"decoration":{"font":{"font":{"desktop":{"value":{"color":"#666666","family":"Noto Sans","weight":"400"}}}}}},"title":{"decoration":{"font":{"font":{"desktop":{"value":{"size":"18px","lineHeight":"1.4em","family":"Noto Sans","weight":"600","color":"#000864"}},"tablet":{"value":{"size":"16px"}},"phone":{"value":{"size":"15px"}}}}}},"post":{"decoration":{"border":{"desktop":{"value":{"radius":{"sync":"on","topLeft":"12px","topRight":"12px","bottomRight":"12px","bottomLeft":"12px"}}}}},"advanced":{"number":{"desktop":{"value":"3"}},"categories":{"desktop":{"value":["all"]}},"offset":{"desktop":{"value":"0"}}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"Related Posts Grid"}}}},"builderVersion":"5.0.0-public-beta.8"} --><!-- /wp:divi/blog -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Blog CTA"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA Column"}}},"decoration":{}}} -->\n<!-- wp:divi/code {"content":{"innerContent":{"desktop":{"value":"<div class=\\"dw-blog-cta\\">\\n  <h2>Ready to Transform Your Factory?</h2>\\n  <p>Talk to our manufacturing ERP specialists about your specific challenges. No demos, no pressure — just expert advice.</p>\\n  <a href=\\"/demo/\\" class=\\"dw-blog-cta-btn\\">Let\'s Talk</a>\\n</div>"}}},"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA Gradient"}}}}} /-->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100440;
DELETE FROM wp_postmeta WHERE post_id = 100440 AND meta_key = '_et_pb_custom_css';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100440, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* ═══ DigiWin Blog Single Body Layout ═══ */\n/* Key insight: each section gets a cssClass (dw-hero-sec, dw-content-sec,\n   dw-related-sec, dw-cta-sec) so we can target modules WITHIN each section\n   without relying on wrapper-div nesting (which doesn\'t work in Divi 5). */\n\n/* --- Divi global overrides for body layout --- */\n.et-l--body .et_pb_section[class] { padding: 0 !important; }\n.et-l--body .et_pb_row { max-width: 100% !important; width: 100% !important; padding: 0 !important; }\n.et-l--body .et_pb_column { padding: 0 !important; }\n\n/* ═══ HERO SECTION ═══ */\n/* Divi framework resets body layout section backgrounds with specificity 0-4-0:\n   .et-l--body .et_pb_section[class*="tb_body"].et_section_regular { background: none !important }\n   We need 0-5-0 to beat it (adding .et_section_regular to our selector). */\n.et-l--body .et_pb_section.et_pb_section_0_tb_body.et_section_regular[class] {\n  background: linear-gradient(135deg, #000432 0%, #000864 40%, #001080 100%) !important;\n  position: relative;\n  overflow: hidden;\n}\n.et_pb_section_0_tb_body::before {\n  content: \'\';\n  position: absolute;\n  top: -50%;\n  right: -20%;\n  width: 80%;\n  height: 200%;\n  background: radial-gradient(ellipse, rgba(0,175,240,0.08) 0%, transparent 60%);\n  pointer-events: none;\n  z-index: 0;\n}\n/* Back links */\n.dw-blog-back-link {\n  display: inline-flex;\n  align-items: center;\n  gap: 8px;\n  color: rgba(255,255,255,0.7);\n  text-decoration: none;\n  font-size: 14px;\n  font-family: \'Noto Sans\', sans-serif;\n  transition: color 0.3s ease;\n  position: relative;\n  z-index: 1;\n}\n.dw-blog-back-link:hover { color: #00AFF0; }\n.dw-blog-back-link svg { width: 16px; height: 16px; }\n.dw-blog-nav { padding: 120px 24px 0; max-width: 840px; margin: 0 auto; }\n\n/* Post title inside hero — override Divi defaults */\n.et_pb_section_0_tb_body .et_pb_post_title {\n  background: none !important;\n  padding: 16px 24px 60px !important;\n  max-width: 840px;\n  margin: 0 auto;\n  position: relative;\n  z-index: 1;\n}\n.et_pb_section_0_tb_body .et_pb_post_title .entry-title {\n  color: #fff !important;\n  font-family: \'Noto Sans\', sans-serif !important;\n  font-size: 42px !important;\n  font-weight: 700 !important;\n  line-height: 1.2 !important;\n  margin-bottom: 16px !important;\n}\n.et_pb_section_0_tb_body .et_pb_post_title .post-meta {\n  color: rgba(255,255,255,0.7) !important;\n  font-size: 14px !important;\n  font-family: \'Noto Sans\', sans-serif !important;\n}\n.et_pb_section_0_tb_body .et_pb_post_title .post-meta a {\n  color: rgba(255,255,255,0.8) !important;\n}\n\n/* Category badge (rendered by postTitleModule categories) */\n.et_pb_section_0_tb_body .et_pb_post_title .entry-categories a {\n  display: inline-block;\n  background: rgba(0,175,240,0.15);\n  color: #00AFF0 !important;\n  font-size: 12px;\n  font-weight: 600;\n  font-family: \'JetBrains Mono\', \'Noto Sans\', monospace;\n  text-transform: uppercase;\n  letter-spacing: 0.1em;\n  padding: 4px 12px;\n  border-radius: 4px;\n  text-decoration: none;\n}\n\n/* ═══ CONTENT SECTION ═══ */\n.et-l--body .et_pb_section.et_pb_section_1_tb_body.et_section_regular[class] {\n  background: #fff !important;\n}\n.et_pb_section_1_tb_body .et_pb_post_content {\n  max-width: 760px;\n  margin: 0 auto;\n  padding: 60px 24px 80px;\n}\n.et_pb_section_1_tb_body .et_pb_post_content h2 {\n  color: #000864 !important;\n  font-size: 28px !important;\n  font-weight: 600 !important;\n  margin: 48px 0 16px !important;\n  line-height: 1.3 !important;\n}\n.et_pb_section_1_tb_body .et_pb_post_content h3 {\n  color: #000864 !important;\n  font-size: 22px !important;\n  font-weight: 600 !important;\n  margin: 36px 0 12px !important;\n  line-height: 1.35 !important;\n}\n.et_pb_section_1_tb_body .et_pb_post_content p {\n  font-size: 16px !important;\n  line-height: 1.8 !important;\n  color: #333 !important;\n  margin-bottom: 20px !important;\n  padding-bottom: 0 !important;\n}\n.et_pb_section_1_tb_body .et_pb_post_content ul,\n.et_pb_section_1_tb_body .et_pb_post_content ol {\n  margin: 16px 0 24px 24px;\n  font-size: 16px;\n  line-height: 1.8;\n  color: #333;\n}\n.et_pb_section_1_tb_body .et_pb_post_content blockquote {\n  border-left: 4px solid #00AFF0;\n  margin: 32px 0;\n  padding: 16px 24px;\n  background: #f8fafc;\n  border-radius: 0 8px 8px 0;\n  font-style: italic;\n  color: #555;\n}\n.et_pb_section_1_tb_body .et_pb_post_content a {\n  color: #00AFF0 !important;\n  text-decoration: underline !important;\n  text-underline-offset: 2px;\n}\n.et_pb_section_1_tb_body .et_pb_post_content img {\n  max-width: 100%;\n  height: auto;\n  border-radius: 8px;\n  margin: 24px 0;\n}\n\n/* ═══ RELATED SECTION ═══ */\n.et-l--body .et_pb_section.et_pb_section_2_tb_body.et_section_regular[class] {\n  background: #F5F7FA !important;\n  padding: 80px 24px !important;\n}\n.dw-blog-related-heading {\n  font-family: \'Noto Sans\', sans-serif;\n  font-size: 32px;\n  font-weight: 600;\n  color: #000864;\n  text-align: center;\n  margin-bottom: 48px;\n}\n.et_pb_section_2_tb_body .et_pb_blog_grid .et_pb_post {\n  background: #fff;\n  border-radius: 12px;\n  overflow: hidden;\n  box-shadow: 0 2px 12px rgba(0,0,0,0.06);\n  transition: transform 0.3s ease, box-shadow 0.3s ease;\n}\n.et_pb_section_2_tb_body .et_pb_blog_grid .et_pb_post:hover {\n  transform: translateY(-4px);\n  box-shadow: 0 8px 24px rgba(0,0,0,0.1);\n}\n\n/* ═══ CTA SECTION (dw-cta-sec) ═══ */\n.dw-blog-cta {\n  background: linear-gradient(135deg, #000864 0%, #003CC8 50%, #00AFF0 100%);\n  padding: 80px 24px;\n  text-align: center;\n  position: relative;\n  overflow: hidden;\n}\n.dw-blog-cta::before {\n  content: \'\';\n  position: absolute;\n  inset: 0;\n  background: repeating-linear-gradient(45deg, transparent, transparent 20px, rgba(255,255,255,0.02) 20px, rgba(255,255,255,0.02) 40px);\n  pointer-events: none;\n}\n.dw-blog-cta h2 {\n  font-family: \'Noto Sans\', sans-serif;\n  font-size: 36px;\n  font-weight: 700;\n  color: #fff;\n  margin: 0 0 16px;\n  position: relative;\n}\n.dw-blog-cta p {\n  font-family: \'Noto Sans\', sans-serif;\n  font-size: 18px;\n  color: rgba(255,255,255,0.85);\n  margin: 0 0 32px;\n  max-width: 600px;\n  margin-left: auto;\n  margin-right: auto;\n  position: relative;\n}\n.dw-blog-cta-btn {\n  display: inline-block;\n  background: #fff;\n  color: #000864;\n  font-family: \'Noto Sans\', sans-serif;\n  font-size: 16px;\n  font-weight: 600;\n  padding: 14px 36px;\n  border-radius: 8px;\n  text-decoration: none;\n  transition: transform 0.3s ease, box-shadow 0.3s ease;\n  position: relative;\n}\n.dw-blog-cta-btn:hover {\n  transform: translateY(-2px);\n  box-shadow: 0 8px 24px rgba(0,0,0,0.2);\n}\n\n/* === NEWS POST OVERRIDES (Industry News category) === */\n/* Conditional back links — blog vs news */\n.dw-back-news { display: none; }\nbody.category-industry-news .dw-back-blog { display: none; }\nbody.category-industry-news .dw-back-news { display: inline-flex; }\n\n/* News hero: taller, background-image set by mu-plugin */\nbody.category-industry-news .et-l--body .et_pb_section.et_pb_section_0_tb_body.et_section_regular[class] {\n  background-size: cover !important;\n  background-position: center !important;\n}\nbody.category-industry-news .dw-blog-nav { padding-top: 140px; }\nbody.category-industry-news .et_pb_section_0_tb_body .et_pb_post_title { padding-bottom: 80px !important; }\n\n/* News category badge: green instead of blue */\nbody.category-industry-news .et_pb_section_0_tb_body .et_pb_post_title .entry-categories a {\n  background: rgba(2,210,140,0.15);\n  color: #02D28C !important;\n}\n\n/* News content: wider reading area */\nbody.category-industry-news .et_pb_section_1_tb_body .et_pb_post_content {\n  max-width: 840px;\n}\n\n/* News related section: dark navy background */\nbody.category-industry-news .et-l--body .et_pb_section.et_pb_section_2_tb_body.et_section_regular[class] {\n  background: linear-gradient(135deg, #000432, #000864) !important;\n}\nbody.category-industry-news .dw-blog-related-heading { color: #fff; }\nbody.category-industry-news .et_pb_section_2_tb_body .et_pb_blog_grid .et_pb_post {\n  background: rgba(255,255,255,0.05);\n  border: 1px solid rgba(255,255,255,0.1);\n}\nbody.category-industry-news .et_pb_section_2_tb_body .et_pb_blog_grid .et_pb_post:hover {\n  background: rgba(255,255,255,0.08);\n  box-shadow: 0 8px 24px rgba(0,0,0,0.3);\n}\nbody.category-industry-news .et_pb_section_2_tb_body .et_pb_blog_grid .entry-title a,\nbody.category-industry-news .et_pb_section_2_tb_body .et_pb_blog_grid .post-meta {\n  color: rgba(255,255,255,0.8) !important;\n}\nbody.category-industry-news .et_pb_section_2_tb_body .et_pb_blog_grid .entry-title a:hover {\n  color: #00AFF0 !important;\n}\n\n/* --- Responsive: 1024px tablet --- */\n@media (max-width: 1024px) {\n  .dw-blog-nav { padding-top: 100px; }\n  body.category-industry-news .dw-blog-nav { padding-top: 120px; }\n  .et_pb_section_0_tb_body .et_pb_post_title .entry-title { font-size: 36px !important; }\n  .et_pb_section_1_tb_body .et_pb_post_content { max-width: 640px; }\n  body.category-industry-news .et_pb_section_1_tb_body .et_pb_post_content { max-width: 700px; }\n  .et_pb_section_1_tb_body .et_pb_post_content h2 { font-size: 24px !important; }\n  .et_pb_section_1_tb_body .et_pb_post_content h3 { font-size: 20px !important; }\n  .et_pb_section_2_tb_body .et_pb_blog_grid { grid-template-columns: repeat(2, 1fr) !important; }\n  .dw-blog-cta h2 { font-size: 32px; }\n}\n\n/* --- Responsive: 768px mobile --- */\n@media (max-width: 768px) {\n  .dw-blog-nav { padding-top: 80px; }\n  .et_pb_section_0_tb_body .et_pb_post_title .entry-title { font-size: 28px !important; line-height: 1.3 !important; }\n  .et_pb_section_0_tb_body .et_pb_post_title { padding-bottom: 40px !important; }\n  .et_pb_section_1_tb_body .et_pb_post_content { max-width: 100%; padding: 40px 16px 60px; }\n  .et_pb_section_2_tb_body { padding: 60px 16px !important; }\n  .dw-blog-related-heading { font-size: 24px; margin-bottom: 32px; }\n  .et_pb_section_2_tb_body .et_pb_blog_grid { grid-template-columns: 1fr !important; }\n  .dw-blog-cta { padding: 60px 16px; }\n  .dw-blog-cta h2 { font-size: 28px; }\n  .dw-blog-back-link { min-height: 44px; padding: 8px 0; }\n  .dw-blog-cta-btn { min-height: 48px; padding: 16px 40px; }\n  /* Touch targets */\n  .et_pb_section_0_tb_body .et_pb_title_meta_container a { display: inline-flex !important; align-items: center !important; min-height: 44px !important; min-width: 44px !important; padding: 0 8px !important; }\n  .et_pb_section_1_tb_body .et_pb_post_content a { display: inline-flex !important; align-items: center !important; min-height: 44px !important; }\n  .et_pb_section_2_tb_body .entry-categories a,\n  .et_pb_section_2_tb_body .more-link,\n  .et_pb_section_2_tb_body .pagination a { display: inline-flex !important; align-items: center !important; min-height: 44px !important; min-width: 44px !important; padding: 0 8px !important; }\n}\n\n/* --- Responsive: 480px small --- */\n@media (max-width: 480px) {\n  .dw-blog-nav { padding-top: 72px; }\n  .et_pb_section_0_tb_body .et_pb_post_title .entry-title { font-size: 24px !important; }\n  .et_pb_section_1_tb_body .et_pb_post_content p { font-size: 15px !important; line-height: 1.75 !important; }\n  .et_pb_section_1_tb_body .et_pb_post_content blockquote { padding: 12px 16px; }\n  .dw-blog-cta-btn { display: block; width: 100%; text-align: center; }\n}\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}');
